const windowDays = 14;
const windowStart = new Date();
windowStart.setDate(windowStart.getDate() + 1);
const windowEnd = new Date();
windowEnd.setDate(windowEnd.getDate() + windowDays);
return [{ json: {
  window_start: windowStart.toISOString().split('T')[0],
  window_end:   windowEnd.toISOString().split('T')[0],
  window_days:  windowDays,
  run_at:       new Date().toISOString()
}}];

const result = $input.first().json;
const ctx    = $('Set Booking Window').first().json;
const count  = parseInt(result.slots_created || result.count || 0);
return [{ json: {
  ...ctx,
  slots_created: count,
  health_status: count >= 0 ? 'ok' : 'error',
  summary: 'Generated ' + count + ' new appointment slots for the next ' + ctx.window_days + ' days (active clinics + doctors with services only)'
}}];
